import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { Magia } from '../models/magias';

@Injectable({
  providedIn: 'root'
})
export class MagicService {
  private apiUrl = 'https://ced.discloud.app/api/magias';

  constructor(private http: HttpClient) { }

  getMagias(): Observable<Magia[]> {
    return this.http.get<Magia[]>(`${this.apiUrl}`);
  }

  getMagiaDetalhe(id: string): Observable<Magia> {
    return this.http.get<Magia>(`${this.apiUrl}/${id}`);
  }

}
